function vbpLinkAutocomplete(){return{isOpen:!1,isLoading:!1,searchQuery:"",results:[],activeIndex:-1,debounceTimer:null,field:"",itemIndex:null,init:function(){this.$watch("searchQuery",this.handleSearch.bind(this))},handleSearch:function(e){var t=this;return this.debounceTimer&&clearTimeout(this.debounceTimer),!e||e.length<2||e.startsWith("http://")||e.startsWith("https://")||e.startsWith("mailto:")||e.startsWith("tel:")?(this.results=[],void(this.isOpen=!1)):void(this.debounceTimer=setTimeout(function(){t.performSearch(e)},300))},performSearch:function(e){var t=this;this.isLoading=!0,this.isOpen=!0,fetch(VBP_Config.restUrl+"search-posts?search="+encodeURIComponent(e),{method:"GET",headers:{"Content-Type":"application/json","X-WP-Nonce":VBP_Config.restNonce}}).then(function(e){return e.json()}).then(function(e){t.results=e.results||[],t.activeIndex=-1,t.isLoading=!1}).catch(function(e){console.error("Error buscando posts:",e),t.results=[],t.isLoading=!1})},selectResult:function(e){this.searchQuery=e.url,this.results=[],this.isOpen=!1,this.$dispatch("link-selected",{url:e.url})},handleKeydown:function(e){if(this.isOpen&&0!==this.results.length)switch(e.key){case"ArrowDown":e.preventDefault(),this.activeIndex=Math.min(this.activeIndex+1,this.results.length-1);break;case"ArrowUp":e.preventDefault(),this.activeIndex=Math.max(this.activeIndex-1,0);break;case"Enter":e.preventDefault(),this.activeIndex>=0&&this.results[this.activeIndex]&&this.selectResult(this.results[this.activeIndex]);break;case"Escape":this.isOpen=!1}},closeDropdown:function(){var e=this;setTimeout(function(){e.isOpen=!1},200)},getTypeLabel:function(e){return{post:"Entrada",page:"Página",flavor_landing:"Landing",category:"Categoría"}[e]||e}}}window.vbpLinkAutocomplete=vbpLinkAutocomplete;